const body = $json.body || $json;
const topics = body.topics || [];
const frequency = body.frequency || 'daily';
const email = body.email || '';

const errors = [];
if (!Array.isArray(topics) || topics.length === 0) {
  errors.push('At least one topic is required');
}
if (!email || !email.includes('@')) {
  errors.push('A valid email address is required');
}

if (errors.length > 0) {
  return [{ json: { valid: false, error: errors.join('; ') } }];
}

const digestId = Array.from({length: 32}, () => Math.random().toString(36)[2]).join('');

return [{ json: {
  valid: true,
  digest_id: digestId,
  topics: JSON.stringify(topics.map(String)),
  frequency: ['daily', 'weekly'].includes(frequency) ? frequency : 'daily',
  email: email.trim(),
  status: 'active',
  source: 'frontend'
}}];

const record = $json.fields || $json;
let topics = [];
try {
  topics = typeof record.topics === 'string' ? JSON.parse(record.topics) : (record.topics || []);
} catch (e) {
  topics = [record.topics].filter(Boolean);
}

// Build a search query from topics
const query = topics.join(' OR ');
const digestId = record.id || record.record_id || '';
const email = record.email || '';

return [{
  json: {
    digest_record_id: digestId,
    topics: topics,
    email: email,
    search_query: query
  }
}];

const rssText = $json.data || $json.body || $json || '';
const topics = $('Prepare Digest Query').first().json.topics;

const items = [];
const itemRegex = /<item[\s\S]*?<\/item>/gi;
const rawStr = typeof rssText === 'string' ? rssText : JSON.stringify(rssText);
const matches = rawStr.match(itemRegex) || [];

for (const match of matches.slice(0, 20)) {
  const titleMatch = match.match(/<title><!\[CDATA\[(.*?)\]\]>|<title>(.*?)<\/title>/);
  const linkMatch = match.match(/<link>(.*?)<\/link>/);
  const descMatch = match.match(/<description><!\[CDATA\[(.*?)\]\]>|<description>(.*?)<\/description>/s);
  const pubDateMatch = match.match(/<pubDate>(.*?)<\/pubDate>/);
  const sourceMatch = match.match(/<source[^>]*>(.*?)<\/source>/);

  const title = (titleMatch?.[1] || titleMatch?.[2] || 'Untitled').trim();
  const link = (linkMatch?.[1] || '').trim();
  const source = (sourceMatch?.[1] || '').trim();

  // Clean description: decode entities FIRST, then strip HTML tags
  let description = (descMatch?.[1] || descMatch?.[2] || '').trim();
  description = description.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'");
  description = description.replace(/<[^>]*>/g, '').trim();
  // If description is mostly a URL, same as title, or empty — use source
  if (!description || description.match(/^https?:\/\//) || description.toLowerCase() === title.toLowerCase()) {
    description = source ? `Source: ${source}` : '';
  }

  const pubDate = (pubDateMatch?.[1] || '').trim();
  items.push({ title, link, description: description.slice(0, 200), pubDate, source });
}

