const unique = items.filter(a => {
  const key = a.title.toLowerCase();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
}).slice(0, 10);

const summaryInput = unique.map((a, i) =>
  `${i + 1}. ${a.title}${a.source ? ' (' + a.source + ')' : ''}`
).join('\n\n');

return [{
  json: {
    articles: unique,
    summary_input: summaryInput || 'No articles found for topics: ' + topics.join(', '),
