  json: {
    digest_record_id: digestRecordId,
    email: email,
    html_content: html,
    summary: summary,
    item_count: itemCount,
    sent_at: new Date().toISOString()
  }
}];

const items = $input.all();
if (!items || items.length === 0 || !items[0].json || Object.keys(items[0].json).length === 0) {
