  description = description.replace(/<[^>]*>/g, '').trim();
  if (!description || description.match(/^https?:\/\//) || description.toLowerCase() === title.toLowerCase()) {
    description = source ? 'Source: ' + source : '';
  }

  if (title) {
    items.push({ title, link, source, description, pubDate: pubDateMatch?.[1] || '' });
  }
}

const articleSummaries = items.map((a, i) =>
  (i + 1) + '. ' + a.title + (a.source ? ' (' + a.source + ')' : '') + (a.description && a.description !== 'Source: ' + a.source ? ' — ' + a.description : '')
).join('\n');

return [{
  json: {
    topic: topic,
    articles: items,
    item_count: items.length,
    articles_text: articleSummaries
  }
}];

