const ollamaResponse = $json;
let summary = ollamaResponse.message?.content || ollamaResponse.response || 'No summary generated.';
const meta = $('Build On-Demand Input').first().json;
const articles = meta.articles || [];
const topics = meta.topics || [];
const itemCount = meta.item_count || 0;

// Markdown fallback
if (summary.includes('**') || summary.match(/^\* /m) || summary.match(/^#{1,3} /m)) {
  summary = summary
    .replace(/^### (.+)$/gm, '<h3>$1</h3>')
    .replace(/^## (.+)$/gm, '<h3>$1</h3>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/^\* (.+)$/gm, '<li>$1</li>')
    .replace(/^- (.+)$/gm, '<li>$1</li>')
    .replace(/(<li>.*<\/li>\n?)+/g, (m) => '<ul>' + m + '</ul>')
    .replace(/\n{2,}/g, '</p><p>')
    .replace(/\n/g, '<br>');
  summary = '<p>' + summary + '</p>';
  summary = summary.replace(/<p>\s*<h3>/g, '<h3>').replace(/<\/h3>\s*<\/p>/g, '</h3>');
  summary = summary.replace(/<p>\s*<ul>/g, '<ul>').replace(/<\/ul>\s*<\/p>/g, '</ul>');
  summary = summary.replace(/<p>\s*<\/p>/g, '');
} else if (!summary.includes('<')) {
  summary = summary.split(/\n{2,}/).map(p => '<p>' + p.replace(/\n/g, '<br>') + '</p>').join('');
}

const articleLinks = articles.map(a => {
  let desc = '';
  if (a.source && !a.title.includes(a.source)) desc = a.source;
  const descHtml = desc ? `<br><small style="color:#888;">${desc}</small>` : '';
  return `<li style="margin-bottom:8px;"><a href="${a.link}" style="color:#6366f1;text-decoration:none;">${a.title}</a>${descHtml}</li>`;
}).join('');

const html = `
<div style="max-width:600px;margin:0 auto;font-family:sans-serif;color:#333;">
  <h1 style="color:#1a1a2e;border-bottom:2px solid #6366f1;padding-bottom:8px;">Nexus Daily Digest</h1>
  <p style="color:#666;font-size:14px;">Topics: ${topics.join(', ')} | ${itemCount} items</p>
  <div style="background:#f8f9fa;padding:16px;border-radius:8px;margin:16px 0;line-height:1.6;">
    ${summary}
  </div>
  <h2 style="color:#1a1a2e;font-size:16px;">Sources</h2>
  <ul style="padding-left:20px;">${articleLinks}</ul>
  <hr style="border:none;border-top:1px solid #eee;margin-top:24px;">
  <p style="color:#aaa;font-size:12px;">Generated by Nexus Digest Agent</p>
</div>`;

return [{
  json: {
    digest_record_id: meta.digest_record_id,
    html_content: html,
    summary: summary,
    item_count: itemCount,
    sent_at: new Date().toISOString()
  }
}];

const body = $json.body || $json;
const message = (body.message || '').trim();

// Extract search topic from natural language message
// Remove common question patterns to get the core topic
let topic = message
  .replace(/^(what('s| is| are)|tell me|show me|give me|find|look up|search|get|fetch)/i, '')
  .replace(/^(the )?(latest|recent|current|new|breaking|today'?s?|this week'?s?)/i, '')
  .replace(/^(news|updates|articles|stories|headlines|info|information)\b/i, '')
  .replace(/^(about|on|for|regarding|related to|in)/i, '')
  .replace(/[?.!]+$/g, '')
  .trim();

// If extraction left nothing, use the full message as the topic
if (!topic || topic.length < 2) {
  topic = message.replace(/[?.!]+$/g, '').trim();
}

return [{
  json: {
    topic: topic,
    original_message: message,
    session_id: body.session_id || ''
  }
}];

const rssText = $json.data || $json.body || '';
const topic = $('Extract Query Topic').first().json.topic;
const items = [];

const itemMatches = rssText.match(/<item>[\s\S]*?<\/item>/g) || [];

for (const itemXml of itemMatches.slice(0, 8)) {
  const titleMatch = itemXml.match(/<title>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/title>/);
  const linkMatch = itemXml.match(/<link>(.*?)<\/link>/);
  const pubDateMatch = itemXml.match(/<pubDate>(.*?)<\/pubDate>/);
  const sourceMatch = itemXml.match(/<source[^>]*>(.*?)<\/source>/);
  const descMatch = itemXml.match(/<description>(?:<!\[CDATA\[)?(.*?)(?:\]\]>)?<\/description>/s);

  const title = (titleMatch?.[1] || '').trim();
  const link = (linkMatch?.[1] || '').trim();
  const source = (sourceMatch?.[1] || '').trim();

  let description = (descMatch?.[1] || '').trim();
  description = description.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'");
  description = description.replace(/<[^>]*>/g, '').trim();
  if (!description || description.match(/^https?:\/\//) || description.toLowerCase() === title.toLowerCase()) {
    description = source ? 'Source: ' + source : '';
  }

  if (title) {
    items.push({ title, link, source, description, pubDate: pubDateMatch?.[1] || '' });
  }
}

const articleSummaries = items.map((a, i) =>
  (i + 1) + '. ' + a.title + (a.source ? ' (' + a.source + ')' : '') + (a.description && a.description !== 'Source: ' + a.source ? ' — ' + a.description : '')
).join('\n');

return [{
  json: {
    topic: topic,
    articles: items,
    item_count: items.length,
    articles_text: articleSummaries
  }
}];

